class Solution {
public:
    int shortestMatchingSubstring(string s, string p) {
        int minLen = INT_MAX;
        int pos1 = p.find('*');
        int pos2 = p.find('*', pos1 + 1);
        string left = p.substr(0, pos1);
        string mid = p.substr(pos1 + 1, pos2 - pos1 - 1);
        string right = p.substr(pos2 + 1);

        for (int i = 0; i < s.length(); i++) {
            for (int j = i + 1; j <= s.length(); j++) {
                string substr = s.substr(i, j - i);
                int idx = 0;
                bool match = true;
                if (substr.find(left) != 0) continue;
                idx = left.length();
                if (substr.find(mid, idx) != string::npos) {
                    idx = substr.find(mid, idx) + mid.length();
                    if (substr.find(right, idx) != string::npos) {
                        idx = substr.find(right, idx) + right.length();
                        if (idx == substr.length()) {
                            minLen = min(minLen, (int)substr.length());
                        }
                    }
                } else if (substr.find(right, idx) != string::npos) {
                    minLen = min(minLen, (int)substr.length());
                }
            }
        }
        if (minLen == INT_MAX) return -1;
        return minLen;
    }
};
